testing_barrels.usage:
// В тестах любого пакета:
import 'package:aq_schema/security_testing.dart';
import 'package:aq_schema/data_testing.dart';

// Используем моки — без dart_vault, без aq_security
final repo = InMemoryDirectRepository<StorableUser>();
final auth = MockSecurityService.alwaysAllow();

scenarios.example:
// ❌ Плохо — ручная сборка в каждом тесте
final backend = MockSecurityBackend();
backend.addUser(user);
backend.addRole(role);
backend.assignRole(userId, roleId);

// ✅ Хорошо — именованный сценарий
final backend = MockSecurityBackend.withAdmin();
final service = MockSecurityService(backend);
final protocol = MockVaultSecurityProtocol(backend);
// Оба видят одного admin пользователя

spec_contract.example:
/// MockSecurityService.loginWithEmail()
///
/// Гарантии реализации (aq_security обязан соблюдать):
/// - Верные credentials → возвращает AuthResponse с user + session + tokens
/// - Неверный пароль → throws AuthException('invalid_credentials')
/// - Несуществующий email → throws AuthException('user_not_found')
/// - Неверифицированный email → throws AuthException('email_not_verified')
/// - Заблокированный пользователь → throws AuthException('user_disabled')

example.backend_structure:
// mock_security_backend.dart
final class MockSecurityBackend {
  // Общее состояние
  final Map<String, AqUser> users = {};
  final Map<String, AqSession> sessions = {};
  final Map<String, AqRole> roles = {};
  final Map<String, List<AqUserRole>> userRoles = {};
  final List<AqAccessPolicy> policies = [];
  final Set<String> revokedTokens = {};
  final List<AqAccessLog> accessLogs = [];

  // Именованные сценарии
  factory MockSecurityBackend.empty() => MockSecurityBackend._();

  factory MockSecurityBackend.withAdmin() {
    final b = MockSecurityBackend._();
    b.users[MockSecuritySeed.adminId] = MockSecuritySeed.adminUser;
    b.roles[MockSecuritySeed.adminRoleId] = MockSecuritySeed.adminRole;
    b.userRoles[MockSecuritySeed.adminId] = [MockSecuritySeed.adminUserRole];
    return b;
  }

  factory MockSecurityBackend.withPolicies() {
    final b = MockSecurityBackend.withAdmin();
    b.policies.addAll(MockSecuritySeed.defaultPolicies);
    return b;
  }

  factory MockSecurityBackend.multiTenant() {
    final b = MockSecurityBackend._();
    b.users[MockSecuritySeed.tenantAUserId] = MockSecuritySeed.tenantAUser;
    b.users[MockSecuritySeed.tenantBUserId] = MockSecuritySeed.tenantBUser;
    return b;
  }
}

example.ports_usage:
// Все порты используют один backend
final backend = MockSecurityBackend.withAdmin();

final service  = MockSecurityService(backend);
final protocol = MockVaultSecurityProtocol(backend);
final context  = MockAuthContext(backend);
final roles    = MockRoleManagementService(backend);

// Создали сессию через service — protocol её видит
await service.loginWithEmail(email: '...', password: '...');
final claims = await protocol.extractClaims(headers); // видит сессию
